/**
 * Rate Limiting Utilities
 * 
 * Protects API endpoints from abuse
 * Uses in-memory store for simplicity (consider Redis for production scale)
 */

interface RateLimitEntry {
  count: number;
  resetAt: number;
}

const rateLimitStore = new Map<string, RateLimitEntry>();

export interface RateLimitConfig {
  maxRequests: number;
  windowMs: number;
}

export const RATE_LIMITS = {
  oauth: { maxRequests: 10, windowMs: 60 * 1000 }, // 10 per minute
  webhook: { maxRequests: 100, windowMs: 60 * 1000 }, // 100 per minute
  api: { maxRequests: 60, windowMs: 60 * 1000 }, // 60 per minute
  uninstall: { maxRequests: 5, windowMs: 60 * 1000 }, // 5 per minute
};

/**
 * Check if request is within rate limit
 */
export function checkRateLimit(
  identifier: string,
  config: RateLimitConfig
): { allowed: boolean; remaining: number; resetAt: number } {
  const now = Date.now();
  const key = identifier;
  
  let entry = rateLimitStore.get(key);
  
  // Clean up expired entries
  if (entry && entry.resetAt < now) {
    rateLimitStore.delete(key);
    entry = undefined;
  }
  
  if (!entry) {
    entry = {
      count: 0,
      resetAt: now + config.windowMs,
    };
    rateLimitStore.set(key, entry);
  }
  
  entry.count++;
  
  const allowed = entry.count <= config.maxRequests;
  const remaining = Math.max(0, config.maxRequests - entry.count);
  
  return {
    allowed,
    remaining,
    resetAt: entry.resetAt,
  };
}

/**
 * Clean up old rate limit entries (call periodically)
 */
export function cleanupRateLimits(): void {
  const now = Date.now();
  
  for (const [key, entry] of rateLimitStore.entries()) {
    if (entry.resetAt < now) {
      rateLimitStore.delete(key);
    }
  }
}

// Cleanup every 5 minutes
if (typeof setInterval !== 'undefined') {
  setInterval(cleanupRateLimits, 5 * 60 * 1000);
}

/**
 * Exponential backoff calculator for retry logic
 */
export function calculateBackoff(attempt: number, baseMs: number = 1000): number {
  const maxBackoff = 32000; // 32 seconds max
  const backoff = Math.min(baseMs * Math.pow(2, attempt), maxBackoff);
  const jitter = Math.random() * 0.1 * backoff; // Add 0-10% jitter
  return Math.floor(backoff + jitter);
}