/**
 * Token Service
 * 
 * Manages OAuth tokens with encryption and automatic refresh
 */

import { createClient } from '@supabase/supabase-js';
import { encrypt, decrypt } from '../utils/encryption';
import { refreshAccessToken, revokeToken } from '../ghl/oauth';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY!;

export class TokenService {
  private supabase = createClient(supabaseUrl, supabaseServiceKey);
  
  /**
   * Store encrypted tokens for a location
   */
  async storeTokens(
    locationId: string,
    accessToken: string,
    refreshToken: string,
    expiresIn: number
  ): Promise<void> {
    const encryptedAccessToken = encrypt(accessToken);
    const encryptedRefreshToken = encrypt(refreshToken);
    const expiresAt = new Date(Date.now() + expiresIn * 1000);
    
    const { error } = await this.supabase
      .from('oauth_tokens')
      .upsert({
        location_id: locationId,
        access_token: encryptedAccessToken,
        refresh_token: encryptedRefreshToken,
        expires_at: expiresAt.toISOString(),
        updated_at: new Date().toISOString(),
      }, {
        onConflict: 'location_id',
      });
    
    if (error) {
      console.error('Failed to store tokens:', error.message);
      throw new Error('Failed to store tokens');
    }
  }
  
  /**
   * Get valid access token (refresh if expired)
   */
  async getValidAccessToken(locationId: string): Promise<string> {
    const { data, error } = await this.supabase
      .from('oauth_tokens')
      .select('*')
      .eq('location_id', locationId)
      .single();
    
    if (error || !data) {
      throw new Error('No tokens found for location');
    }
    
    const expiresAt = new Date(data.expires_at);
    const now = new Date();
    
    // Refresh if token expires in less than 5 minutes
    if (expiresAt.getTime() - now.getTime() < 5 * 60 * 1000) {
      await this.refreshToken(locationId);
      return this.getValidAccessToken(locationId);
    }
    
    return decrypt(data.access_token);
  }
  
  /**
   * Refresh access token
   */
  async refreshToken(locationId: string): Promise<void> {
    const { data, error } = await this.supabase
      .from('oauth_tokens')
      .select('refresh_token')
      .eq('location_id', locationId)
      .single();
    
    if (error || !data) {
      throw new Error('No refresh token found');
    }
    
    const decryptedRefreshToken = decrypt(data.refresh_token);
    
    try {
      const tokenResponse = await refreshAccessToken(decryptedRefreshToken);
      
      await this.storeTokens(
        locationId,
        tokenResponse.access_token,
        tokenResponse.refresh_token,
        tokenResponse.expires_in
      );
    } catch (error) {
      console.error('Token refresh failed:', error);
      throw new Error('Failed to refresh token');
    }
  }
  
  /**
   * Revoke and delete tokens (for uninstall)
   */
  async revokeAndDeleteTokens(locationId: string): Promise<void> {
    try {
      // Get tokens
      const { data } = await this.supabase
        .from('oauth_tokens')
        .select('access_token, refresh_token')
        .eq('location_id', locationId)
        .single();
      
      if (data) {
        // Revoke tokens with GHL
        try {
          const accessToken = decrypt(data.access_token);
          await revokeToken(accessToken);
        } catch (error) {
          console.error('Failed to revoke access token:', error);
        }
        
        try {
          const refreshToken = decrypt(data.refresh_token);
          await revokeToken(refreshToken);
        } catch (error) {
          console.error('Failed to revoke refresh token:', error);
        }
      }
      
      // Delete from database
      await this.supabase
        .from('oauth_tokens')
        .delete()
        .eq('location_id', locationId);
        
    } catch (error) {
      console.error('Error revoking tokens:', error);
      // Continue with deletion even if revocation fails
    }
  }
}