/**
 * GHL Scopes Management
 */

import { GHL_SCOPES, REQUIRED_SCOPES, validateScopes } from '@/config/scopes.config';

export { GHL_SCOPES, REQUIRED_SCOPES, validateScopes };

export function getScopesForInstall(): string {
  return REQUIRED_SCOPES.join(' ');
}

export function getScopesDocumentation(): string {
  return GHL_SCOPES.map(s => 
    `${s.scope}: ${s.rationale} ${s.required ? '(REQUIRED)' : '(OPTIONAL)'}`
  ).join('\n');
}