/**
 * GHL OAuth Scopes Configuration
 * 
 * PRINCIPLE: Request ONLY what is absolutely necessary for core functionality.
 * Each scope must have a clear business justification.
 */

export interface ScopeDefinition {
  scope: string;
  rationale: string;
  required: boolean;
  marketplaceReviewNote: string;
}

export const GHL_SCOPES: ScopeDefinition[] = [
  {
    scope: 'contacts.readonly',
    rationale: 'Read merchant contact information to display in dashboard and calculate lifetime value metrics',
    required: true,
    marketplaceReviewNote: 'Used to identify merchants and aggregate transaction data per merchant',
  },
  {
    scope: 'contacts.write',
    rationale: 'Update merchant records with calculated lifetime value and residual tracking data',
    required: true,
    marketplaceReviewNote: 'Writes custom field values for LTV tracking. Does not create/delete contacts.',
  },
  {
    scope: 'locations.readonly',
    rationale: 'Retrieve location details for multi-location agency support and proper data isolation',
    required: true,
    marketplaceReviewNote: 'Essential for multi-tenancy. Each location gets isolated data view.',
  },
  {
    scope: 'webhooks.write',
    rationale: 'Create webhooks to receive real-time notifications when merchant data changes',
    required: false,
    marketplaceReviewNote: 'Optional. Only created if user enables real-time sync. Fully removed on uninstall.',
  },
];

export const REQUIRED_SCOPES = GHL_SCOPES
  .filter(s => s.required)
  .map(s => s.scope);

export const ALL_SCOPES = GHL_SCOPES.map(s => s.scope);

export function getScopeString(includeOptional: boolean = false): string {
  const scopes = includeOptional ? ALL_SCOPES : REQUIRED_SCOPES;
  return scopes.join(' ');
}

export function validateScopes(grantedScopes: string[]): {
  valid: boolean;
  missing: string[];
} {
  const missing = REQUIRED_SCOPES.filter(s => !grantedScopes.includes(s));
  return {
    valid: missing.length === 0,
    missing,
  };
}