/**
 * GHL Webhook Receiver
 * 
 * Handles incoming webhooks from GoHighLevel
 */

import { NextRequest, NextResponse } from 'next/server';
import { checkRateLimit, RATE_LIMITS } from '@/lib/utils/rate-limit';
import { createAdminClient } from '@/lib/supabase/admin';
import { InstallationService } from '@/lib/services/installation.service';

export async function POST(request: NextRequest) {
  try {
    // Rate limiting
    const ip = request.headers.get('x-forwarded-for') || 'unknown';
    const rateLimit = checkRateLimit(`webhook:${ip}`, RATE_LIMITS.webhook);
    
    if (!rateLimit.allowed) {
      return NextResponse.json(
        { error: 'Too many requests' },
        { status: 429 }
      );
    }

    const payload = await request.json();
    const { type, locationId, data } = payload;

    if (!locationId) {
      return NextResponse.json(
        { error: 'Missing locationId' },
        { status: 400 }
      );
    }

    // Verify installation is active
    const installationService = new InstallationService();
    const isActive = await installationService.isInstallationActive(locationId);

    if (!isActive) {
      console.log(`Webhook received for inactive installation: ${locationId}`);
      return NextResponse.json(
        { error: 'Installation not active' },
        { status: 403 }
      );
    }

    // Log webhook event
    const supabase = createAdminClient();
    await supabase.rpc('log_audit_event', {
      loc_id: locationId,
      evt_type: 'webhook_received',
      evt_data: {
        webhook_type: type,
        data_keys: Object.keys(data || {}),
      },
    });

    // Process webhook based on type
    switch (type) {
      case 'contact.created':
      case 'contact.updated':
        // Handle contact changes
        console.log(`Contact ${type} for location ${locationId}`);
        // Add your business logic here
        break;

      case 'contact.deleted':
        // Handle contact deletion
        console.log(`Contact deleted for location ${locationId}`);
        break;

      default:
        console.log(`Unknown webhook type: ${type}`);
    }

    return NextResponse.json({ received: true });
  } catch (error) {
    console.error('Webhook processing error:', error);
    return NextResponse.json(
      { error: 'Webhook processing failed' },
      { status: 500 }
    );
  }
}

